// scripts/rename-evenkeel.mjs
//
// One-shot rename: KeelLearn → Even Keel Learning, KeLe → Eke.
// Walks the repo, replaces strings in source / docs / configs.
// Skips: node_modules, .next, .git, evidence/ (historical), reports/AUDIT_REPORT.md
// (regenerated), package-lock.json (regenerated by npm), this script itself,
// and the rename script.
//
// Order of replacements is significant: longer / more specific patterns run
// first so they don't get clipped by later substring matches (e.g.
// "keellearn" contains "kele").
//
// Run with:  node scripts/rename-evenkeel.mjs
//
// To preview without writing:  node scripts/rename-evenkeel.mjs --dry

import { promises as fs } from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const ROOT = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const DRY = process.argv.includes("--dry");

const SKIP_DIRS = new Set(["node_modules", ".next", ".git", "evidence"]);
const SKIP_FILES = new Set([
  "package-lock.json",
  "rename-evenkeel.mjs",
]);
const ALLOWED_EXT = new Set([
  ".ts", ".tsx", ".md", ".css", ".json", ".mjs", ".html", ".ps1", ".txt", ".js",
]);

// Order matters. Longer / case-specific first.
const REPLACEMENTS = [
  // Platform name — uppercase shouting form
  [/KEELLEARN/g, "EVENKEEL"],
  // Platform name — pascal-case display form
  [/KeelLearn/g, "Even Keel Learning"],
  // Platform name — lowercase package / codename
  [/keellearn/g, "evenkeel"],

  // AI persona — uppercase shouting form
  [/\bKELE\b/g, "EKE"],
  // AI persona — original pascal-case "KeLe"
  [/\bKeLe\b/g, "Eke"],
  // AI persona — also "KeLe" inside identifiers like "KeLeEngine", "KeLeChat"
  [/KeLe([A-Z])/g, "Eke$1"],
  // AI persona — lowercase, identifier-or-token boundaries.
  // Match where preceded by start, /, -, _, ", ', `, (, [, {, =, :, space, .
  // and followed by similar (so we hit "kele.greeting", "kele-engine",
  // "lib/kele/", "kele" but NOT "keele" or substrings).
  [/(^|[\s\/\\\-_'"`(\[{=:;,.])kele(?=[\s\/\\\-_'"`)\]}=:;,.]|$)/g, "$1eke"],
];

async function* walk(dir) {
  for (const entry of await fs.readdir(dir, { withFileTypes: true })) {
    if (SKIP_FILES.has(entry.name)) continue;
    const full = path.join(dir, entry.name);
    if (entry.isDirectory()) {
      if (SKIP_DIRS.has(entry.name)) continue;
      yield* walk(full);
    } else if (entry.isFile()) {
      yield full;
    }
  }
}

function shouldProcess(file) {
  if (file.endsWith("scripts/rename-evenkeel.mjs")) return false;
  if (file.endsWith("scripts\\rename-evenkeel.mjs")) return false;
  // Don't rewrite the historical audit report (will be regenerated).
  if (file.endsWith(path.join("reports", "AUDIT_REPORT.md"))) return false;
  // Skip historical compliance map regenerated artifact? Keep it; it has live refs.
  const ext = path.extname(file);
  return ALLOWED_EXT.has(ext);
}

let touched = 0;
let totalReplacements = 0;

for await (const file of walk(ROOT)) {
  if (!shouldProcess(file)) continue;
  const before = await fs.readFile(file, "utf8");
  let after = before;
  let fileCount = 0;
  for (const [rx, sub] of REPLACEMENTS) {
    after = after.replace(rx, (...args) => {
      fileCount++;
      // Some patterns have a captured prefix in $1 — pass through.
      if (typeof sub === "string" && sub.includes("$1")) {
        return sub.replace("$1", args[1] ?? "");
      }
      return sub;
    });
  }
  if (fileCount > 0 && after !== before) {
    if (!DRY) await fs.writeFile(file, after, "utf8");
    const rel = path.relative(ROOT, file);
    console.log(`  ${rel}  (${fileCount} replacements)`);
    touched++;
    totalReplacements += fileCount;
  }
}

console.log("");
console.log(
  `${DRY ? "[DRY RUN] " : ""}Touched ${touched} files, ${totalReplacements} replacements.`,
);
